#include <stdio.h>
#include <stdlib.h>
#include <string.h>

long long power(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1)
            res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

long long modInverse(long long a, long long m) {
    long long m0 = m;
    long long y = 0, x = 1;
    if (m == 1)
        return 0;
    while (a > 1) {
        long long q = a / m;
        long long t = m;
        m = a % m, a = t;
        t = y;
        y = x - q * y;
        x = t;
    }
    if (x < 0)
        x += m0;
    return x;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[1000001], B[10001];
        int L;
        scanf("%s %s %d", A, B, &L);
        long long a = 0, b = 0;
        int lenA = strlen(A), lenB = strlen(B);
        for (int i = 0; i < lenA; i++)
            a = (a * 7 + A[i] - '0') % power(7, L, 7);
        for (int i = 0; i < lenB; i++)
            b = (b * 7 + B[i] - '0') % power(7, L, 7);
        long long c = (a * modInverse(b, power(7, L, 7))) % power(7, L, 7);
        printf("%lld\n", c);
    }
    return 0;
}

