import java.util.Scanner;
public class Main {
    public static long power(long a, long b, long mod) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1)
                res = (res * a) % mod;
            a = (a * a) % mod;
            b >>= 1;
        }
        return res;
    }

    public static long modInverse(long a, long m) {
        long m0 = m;
        long y = 0, x = 1;
        if (m == 1)
            return 0;
        while (a > 1) {
            long q = a / m;
            long t = m;
            m = a % m;
            a = t;
            t = y;
            y = x - q * y;
            x = t;
        }
        if (x < 0)
            x += m0;
        return x;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String A = sc.next(), B = sc.next();
            int L = sc.nextInt();
            long a = 0, b = 0;
            int lenA = A.length(), lenB = B.length();
            for (int i = 0; i < lenA; i++)
                a = (a * 7 + A.charAt(i) - '0') % power(7, L, 7);
            for (int i = 0; i < lenB; i++)
                b = (b * 7 + B.charAt(i) - '0') % power(7, L, 7);
            long c = (a * modInverse(b, power(7, L, 7))) % power(7, L, 7);
            System.out.println(c);
        }
    }
}

