function power(a, b, mod) {
    let res = 1;
    while (b > 0) {
        if (b % 2 === 1)
            res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

function modInverse(a, m) {
    let m0 = m;
    let y = 0, x = 1;
    if (m === 1)
        return 0;
    while (a > 1) {
        let q = Math.floor(a / m);
        let t = m;
        m = a % m;
        a = t;
        t = y;
        y = x - q * y;
        x = t;
